#include <stdio.h>
int main() {
    int T, H, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &H, &M);
        int count = 0;
        for (int h = 0; h < H; h++) {
            for (int m = 0; m < M; m++) {
                int h1 = h / 10, h2 = h % 10;
                int m1 = m / 10, m2 = m % 10;
                if ((h1 == h2 && h1 == m1 && h1 == m2) || (h1 == 0 && h2 == m1 && h2 == m2) || (m1 == 0 && h1 == h2 && h1 == m2)) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

